--
-- Name: fighter_recent_form; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.fighter_recent_form AS
 SELECT f.fighter1_id AS fighter_id,
    f.fighter1_name AS fighter_name,
    count(*) AS total_fights,
    sum(
        CASE
            WHEN (f.winner_id = f.fighter1_id) THEN 1
            ELSE 0
        END) AS wins,
    sum(
        CASE
            WHEN ((f.winner_id <> f.fighter1_id) AND (f.winner_id IS NOT NULL)) THEN 1
            ELSE 0
        END) AS losses,
    sum(
        CASE
            WHEN (f.method = 'KO/TKO'::text) THEN 1
            ELSE 0
        END) AS ko_finishes,
    sum(
        CASE
            WHEN (f.method = 'SUB'::text) THEN 1
            ELSE 0
        END) AS sub_finishes,
    avg(f.round) AS avg_fight_length_rounds,
    max(e.date) AS last_fight_date
   FROM (public.fights f
     JOIN public.events e ON ((e.id = f.event_id)))
  GROUP BY f.fighter1_id, f.fighter1_name;


